     1→import React, { useState } from 'react';
     2→import {
     3→  Search,
     4→  Network,
     5→  Cpu,
     6→  BarChart3,
     7→  Loader2,
     8→  AlertTriangle,
     9→  Info,
    10→  RefreshCw,
    11→  Sparkles
    12→} from 'lucide-react';
    13→import api from '../api/axios';
    14→import SemanticSearchTab from '../components/AnalysisWorkbench/SemanticSearchTab';
    15→import NetworkAnalysisTab from '../components/AnalysisWorkbench/NetworkAnalysisTab';
    16→import TechMappingTab from '../components/AnalysisWorkbench/TechMappingTab';
    17→import AnalysisResults from '../components/AnalysisWorkbench/AnalysisResults';
    18→import { motion, AnimatePresence } from 'framer-motion';
    19→
    20→const AnalysisWorkbench = () => {
    21→  const [activeTab, setActiveTab] = useState('semantic');
    22→  const [loading, setLoading] = useState(false);
    23→  const [results, setResults] = useState(null);
    24→  const [error, setError] = useState(null);
    25→
    26→  const handleAnalysis = async (type, params) => {
    27→    setLoading(true);
    28→    setError(null);
    29→
    30→    let endpoint = 'mcp/proxy';
    31→    let data = {
    32→      tool_name: `${type}_analysis_tool_name`,
    33→      arguments: params
    34→    };
    35→
    36→    if (type === 'semantic') {
    37→      endpoint = 'mcp/semantic-search';
    38→      data = params;
    39→    } else if (type === 'network') {
    40→      endpoint = 'mcp/network-analysis';
    41→      data = params;
    42→    } else if (type === 'tech') {
    43→      endpoint = 'mcp/technology-mapping';
    44→      data = params;
    45→    }
    46→
    47→    try {
    48→      const response = await api.post(endpoint, data);
    49→      setResults(response.data);
    50→    } catch (err) {
    51→      setError(err.response?.data?.detail || "An error occurred during analysis pulse.");
    52→    } finally {
    53→      setLoading(false);
    54→    }
    55→  };
    56→
    57→  const tabs = [
    58→    { id: 'semantic', label: 'Semantic Search', icon: Search, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    59→    { id: 'network', label: 'Network Matrix', icon: Network, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    60→    { id: 'tech', label: 'Tech Mapping', icon: Cpu, color: 'text-purple-600', bg: 'bg-purple-50' },
    61→    { id: 'charts', label: 'Visual Analytics', icon: BarChart3, color: 'text-amber-600', bg: 'bg-amber-50' }
    62→  ];
    63→
    64→  return (
    65→    <div className="max-w-7xl mx-auto space-y-10 p-4 pb-20">
    66→      <header className="flex flex-col md:row justify-between items-start md:items-center gap-6">
    67→        <div className="space-y-1">
    68→          <div className="flex items-center gap-2">
    69→            <Sparkles className="w-5 h-5 text-indigo-600" />
    70→            <span className="text-xs font-bold uppercase tracking-widest text-indigo-600/80">Expert Workspace</span>
    71→          </div>
    72→          <h1 className="text-4xl font-black text-slate-900 tracking-tight">
    73→            Analysis Workbench
    74→          </h1>
    75→          <p className="text-slate-500 font-medium max-w-2xl">
    76→            Execute deep-dive patent investigations using multi-vector semantic models and citation graph analysis.
    77→          </p>
    78→        </div>
    79→        <button
    80→          onClick={() => { setResults(null); setError(null); }}
    81→          className="flex items-center gap-2 px-4 py-2 text-sm font-bold text-slate-500 hover:text-indigo-600 transition-colors border border-slate-200 rounded-xl bg-white"
    82→        >
    83→          <RefreshCw className="w-4 h-4" /> Reset Workspace
    84→        </button>
    85→      </header>
    86→
    87→      {/* Tab Navigation */}
    88→      <nav className="flex p-1.5 bg-slate-100 rounded-2xl w-full md:w-fit border border-slate-200/60 shadow-inner overflow-x-auto no-scrollbar">
    89→        {tabs.map(tab => {
    90→          const Icon = tab.icon;
    91→          const isActive = activeTab === tab.id;
    92→          return (
    93→            <button
    94→              key={tab.id}
    95→              className={`relative flex items-center gap-2 px-6 py-3 rounded-xl text-sm font-bold transition-all whitespace-nowrap ${isActive ? 'text-slate-950 translate-y-0 shadow-sm' : 'text-slate-500 hover:text-slate-700'
    96→                }`}
    97→              onClick={() => setActiveTab(tab.id)}
    98→            >
    99→              {isActive && (
   100→                <motion.div
   101→                  layoutId="activeTab"
   102→                  className="absolute inset-0 bg-white rounded-xl -z-10"
   103→                  transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
   104→                />
   105→              )}
   106→              <Icon className={`w-4 h-4 ${isActive ? tab.color : ''}`} />
   107→              {tab.label}
   108→            </button>
   109→          );
   110→        })}
   111→      </nav>
   112→
   113→      <main className="grid grid-cols-1 xl:grid-cols-12 gap-10">
   114→        {/* Input Panel */}
   115→        <div className="xl:col-span-4">
   116→          <section className="premium-card p-8 sticky top-24">
   117→            <h2 className="text-lg font-bold text-slate-900 mb-6 flex items-center gap-2">
   118→              Configuration
   119→            </h2>
   120→            <div className="space-y-6">
   121→              <AnimatePresence mode="wait">
   122→                <motion.div
   123→                  key={activeTab}
   124→                  initial={{ opacity: 0, x: -10 }}
   125→                  animate={{ opacity: 1, x: 0 }}
   126→                  exit={{ opacity: 0, x: 10 }}
   127→                  transition={{ duration: 0.2 }}
   128→                >
   129→                  {activeTab === 'semantic' && (
   130→                    <SemanticSearchTab onSearch={handleAnalysis} loading={loading} />
   131→                  )}
   132→                  {activeTab === 'network' && (
   133→                    <NetworkAnalysisTab onAnalyze={handleAnalysis} loading={loading} />
   134→                  )}
   135→                  {activeTab === 'tech' && (
   136→                    <TechMappingTab onMapping={handleAnalysis} loading={loading} />
   137→                  )}
   138→                  {activeTab === 'charts' && (
   139→                    <div className="text-center py-10 space-y-4">
   140→                      <div className="w-16 h-16 bg-amber-50 rounded-full flex items-center justify-center mx-auto text-amber-600">
   141→                        <BarChart3 className="w-8 h-8" />
   142→                      </div>
   143→                      <p className="text-slate-500 text-sm font-medium">Visualization layer is currently initializing.</p>
   144→                    </div>
   145→                  )}
   146→                </motion.div>
   147→              </AnimatePresence>
   148→            </div>
   149→          </section>
   150→        </div>
   151→
   152→        {/* Results Panel */}
   153→        <div className="xl:col-span-8">
   154→          <AnimatePresence mode="wait">
   155→            {loading ? (
   156→              <motion.div
   157→                initial={{ opacity: 0 }}
   158→                animate={{ opacity: 1 }}
   159→                className="flex flex-col items-center justify-center p-20 bg-slate-50 rounded-3xl border border-dashed border-slate-300"
   160→              >
   161→                <div className="relative">
   162→                  <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
   163→                  <div className="absolute inset-0 blur-xl bg-indigo-500/10 animate-pulse"></div>
   164→                </div>
   165→                <p className="mt-6 text-slate-900 font-bold">Scanning Global Databases...</p>
   166→                <p className="text-slate-500 text-sm mt-1">AI Agents are verifying claims and metadata.</p>
   167→              </motion.div>
   168→            ) : results ? (
   169→              <motion.div
   170→                initial={{ opacity: 0, y: 20 }}
   171→                animate={{ opacity: 1, y: 0 }}
   172→                className="space-y-6"
   173→              >
   174→                <AnalysisResults results={results} />
   175→              </motion.div>
   176→            ) : error ? (
   177→              <motion.div
   178→                initial={{ opacity: 0 }}
   179→                animate={{ opacity: 1 }}
   180→                className="p-8 bg-rose-50 rounded-3xl border border-rose-100 flex items-start gap-4"
   181→              >
   182→                <div className="p-3 bg-rose-100 rounded-xl text-rose-600">
   183→                  <AlertTriangle className="w-6 h-6" />
   184→                </div>
   185→                <div>
   186→                  <h3 className="text-rose-900 font-bold mb-1">Analysis Interrupted</h3>
   187→                  <p className="text-rose-700 text-sm">{error}</p>
   188→                </div>
   189→              </motion.div>
   190→            ) : (
   191→              <motion.div
   192→                initial={{ opacity: 0 }}
   193→                animate={{ opacity: 1 }}
   194→                className="flex flex-col items-center justify-center p-20 bg-white rounded-3xl border border-slate-200 border-dashed"
   195→              >
   196→                <div className="p-6 bg-slate-50 rounded-full mb-6">
   197→                  <Info className="w-10 h-10 text-slate-300" />
   198→                </div>
   199→                <h3 className="text-slate-900 font-bold text-lg mb-2">Ready for Investigation</h3>
   200→                <p className="text-slate-500 text-center max-w-sm">
   201→                  Configure your analysis parameters on the left to begin searching our high-fidelity patent cluster.
   202→                </p>
   203→              </motion.div>
   204→            )}
   205→          </AnimatePresence>
   206→        </div>
   207→      </main>
   208→    </div>
   209→  );
   210→};
   211→
   212→export default AnalysisWorkbench;
   213→

