    62→        const loadNodes = () => {
    63→            const nextBatch = rawNodes.slice(nodeIndex, nodeIndex + BATCH_SIZE);
    64→            if (nextBatch.length === 0) {
    65→                loadEdges();
    66→                return;
    67→            }
    68→
    69→            const newNodes = nextBatch.map((node, idx) => ({
    70→                id: node.id,
    71→                data: { label: node.label || node.id },
    72→                position: {
    73→                    x: Math.random() * 800 - 400 + (nodeIndex + idx) * 10,
    74→                    y: Math.random() * 600 - 300
    75→                },
    76→                style: {
    77→                    background: NODE_COLORS[node.group] || NODE_COLORS.Default,
    78→                    color: '#fff',
    79→                    borderRadius: '12px',
    80→                    padding: '10px',
    81→                    fontSize: '12px',
    82→                    fontWeight: 'bold',
    83→                    width: 150,
    84→                    textAlign: 'center',
    85→                    boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)',
    86→                    border: 'none'
    87→                }
    88→            }));
    89→
    90→            setNodes((nds) => [...nds, ...newNodes]);
    91→            nodeIndex += BATCH_SIZE;
    92→            itemsProcessed += nextBatch.length;
    93→            if (totalItems > 0) {
    94→                setProgress(Math.round((itemsProcessed / totalItems) * 100));
    95→            }
    96→
    97→            setTimeout(loadNodes, BATCH_DELAY);
    98→        };
    99→
   100→        // Process edges in batches
   101→        let edgeIndex = 0;
   102→        const loadEdges = () => {
   103→            const nextBatch = rawEdges.slice(edgeIndex, edgeIndex + BATCH_SIZE);
   104→            if (nextBatch.length === 0) {
   105→                setLoading(false);
   106→                setProgress(100);
   107→                return;
   108→            }
   109→
   110→            const newEdges = nextBatch.map((edge) => ({
   111→                id: `e-${edge.from}-${edge.to}`,
   112→                source: edge.from,
   113→                target: edge.to,
   114→                label: edge.label,
   115→                animated: true,
   116→                style: { stroke: '#94a3b8', strokeWidth: 2 },
   117→                labelStyle: { fill: '#64748b', fontWeight: 700, fontSize: 10 },
   118→                markerEnd: {
   119→                    type: MarkerType.ArrowClosed,
   120→                    color: '#94a3b8',
   121→                },
   122→            }));
   123→
   124→            setEdges((eds) => [...eds, ...newEdges]);
   125→            edgeIndex += BATCH_SIZE;
   126→            itemsProcessed += nextBatch.length;
   127→            if (totalItems > 0) {
   128→                setProgress(Math.round((itemsProcessed / totalItems) * 100));
   129→            }
   130→
   131→            setTimeout(loadEdges, BATCH_DELAY);
   132→        };
   133→
   134→        loadNodes();
   135→
   136→        return () => {
   137→            // Cleanup could go here if needed
   138→        };
   139→    }, [data, setNodes, setEdges]);
   140→
   141→    if (!data?.nodes || data.nodes.length === 0) {
   142→        return (
   143→            <div className="flex flex-col items-center justify-center p-12 bg-gray-50 rounded-3xl border-2 border-dashed border-gray-200">
