   168→                onEdgesChange={onEdgesChange}
   169→                fitView
   170→                className="bg-gray-50/50"
   171→            >
   172→                <Background color="#e2e8f0" gap={20} />
   173→                <Controls />
   174→                <MiniMap
   175→                    nodeColor={(n) => n.style?.background || '#eee'}
   176→                    maskColor="rgb(241, 245, 249, 0.6)"
   177→                    className="rounded-xl border border-gray-200 shadow-sm"
   178→                />
   179→
   180→                {/* Floating Tools HUD */}
   181→                <div className="absolute top-4 right-4 flex flex-col gap-2 z-20">
   182→                    <div className="bg-white/90 backdrop-blur-md p-3 rounded-2xl shadow-lg border border-gray-100 flex flex-col gap-3">
