   189→                            <span className="text-[10px] font-bold text-gray-500">Technology</span>
   190→                        </div>
   191→                        <div className="flex items-center gap-2">
   192→                            <div className="w-3 h-3 rounded-full bg-[#10b981]"></div>
   193→                            <span className="text-[10px] font-bold text-gray-500">Patent</span>
   194→                        </div>
