            const response = await fetch(`${API_URL}/api/v1/reports/generate`, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    topic: newReport.topic,
                    report_type: newReport.report_type,
                    patent_ids: patentIds,
                    priority: 'normal'
                })
            });

