     6→// Transform API result data into graph format for visualization
     7→const transformResultToGraph = (data, tabType) => {
     8→    if (!data || !Array.isArray(data) || data.length === 0) return null;
     9→
    10→    const nodes = [];
    11→    const edges = [];
    12→    const nodeIds = new Set();
    13→
    14→    if (tabType === 'competitor') {
    15→        // Competitor data: [{company, competitor, strength}]
    16→        data.forEach((item, idx) => {
    17→            if (item.company && !nodeIds.has(item.company)) {
    18→                nodes.push({ id: item.company, label: item.company, group: 'Corporation' });
    19→                nodeIds.add(item.company);
    20→            }
    21→            if (item.competitor && !nodeIds.has(item.competitor)) {
    22→                nodes.push({ id: item.competitor, label: item.competitor, group: 'Corporation' });
    23→                nodeIds.add(item.competitor);
    24→            }
    25→            if (item.company && item.competitor) {
    26→                edges.push({ id: `e${idx}`, from: item.company, to: item.competitor });
    27→            }
    28→        });
    29→    } else if (tabType === 'problem') {
    30→        // Problem data: [{problem, solution, patent_number, title}]
    31→        data.forEach((item, idx) => {
    32→            const patentId = item.patent_number || `patent_${idx}`;
    33→            if (!nodeIds.has(patentId)) {
    34→                nodes.push({ id: patentId, label: item.title || patentId, group: 'Patent' });
    35→                nodeIds.add(patentId);
    36→            }
    37→            if (item.problem) {
    38→                const problemId = `problem_${idx}`;
    39→                nodes.push({ id: problemId, label: item.problem.substring(0, 40) + '...', group: 'Default' });
    40→                edges.push({ id: `e_prob_${idx}`, from: patentId, to: problemId });
    41→            }
    42→            if (item.solution) {
    43→                const solutionId = `solution_${idx}`;
    44→                nodes.push({ id: solutionId, label: item.solution.substring(0, 40) + '...', group: 'Technology' });
    45→                edges.push({ id: `e_sol_${idx}`, from: patentId, to: solutionId });
    46→            }
    47→        });
    48→    } else if (tabType === 'cluster') {
    49→        // Cluster data: [{technology_code, technology_level, patent_count, top_patents}]
    50→        data.forEach((item, idx) => {
    51→            const techId = item.technology_code || `tech_${idx}`;
    52→            if (!nodeIds.has(techId)) {
    53→                nodes.push({ id: techId, label: `${techId} (${item.patent_count})`, group: 'Technology' });
    54→                nodeIds.add(techId);
    55→            }
    56→            (item.top_patents || []).forEach((patentTitle, pIdx) => {
    57→                const patentId = `${techId}_patent_${pIdx}`;
    58→                nodes.push({ id: patentId, label: patentTitle?.substring(0, 30) + '...' || patentId, group: 'Patent' });
    59→                edges.push({ id: `e_${techId}_${pIdx}`, from: techId, to: patentId });
    60→            });
    61→        });
    62→    } else if (tabType === 'path') {
    63→        // Path data: [{path_nodes, distance}]
    64→        data.forEach((item, idx) => {
    65→            const pathNodes = item.path_nodes || [];
    66→            pathNodes.forEach((nodeLabel, nIdx) => {
    67→                const nodeId = `path${idx}_node${nIdx}`;
    68→                if (!nodeIds.has(nodeLabel)) {
    69→                    nodes.push({ id: nodeLabel, label: nodeLabel, group: 'Default' });
    70→                    nodeIds.add(nodeLabel);
    71→                }
    72→                if (nIdx > 0) {
    73→                    edges.push({ id: `path${idx}_e${nIdx}`, from: pathNodes[nIdx - 1], to: nodeLabel });
    74→                }
    75→            });
