    10→// Add a request interceptor to add the auth token to headers
    11→api.interceptors.request.use(
    12→    (config) => {
    13→        const token = localStorage.getItem('token');
    14→        if (token) {
    15→            config.headers['Authorization'] = `Bearer ${token}`;
    16→        }
    17→        return config;
    18→    },
    19→    (error) => {
    20→        return Promise.reject(error);
    21→    }
    22→);
    23→
    24→// Add a response interceptor to handle auth errors
    25→api.interceptors.response.use(
    26→    (response) => response,
    27→    (error) => {
    28→        if (error.response && error.response.status === 401) {
    29→            localStorage.removeItem('token');
    30→            // window.location.href = '/login'; // Optional: Redirect to login
    31→        }
    32→        return Promise.reject(error);
    33→    }
    34→);
