     1→import React, { createContext, useContext, useReducer, useEffect, useState } from 'react';
     2→import { getChatbotAPI, checkAuthStatus } from '../api/chatbot_modes';
     3→
     4→// Initial state
     5→const initialState = {
     6→    currentSession: null,
     7→    sessions: [],
     8→    messages: [],
     9→    isLoading: false,
    10→    error: null,
    11→    userProperties: {},
    12→    isConnected: false,
    13→    isInitialized: false,
    14→    authStatus: {
    15→        isAuthenticated: false,
    16→        userId: null,
    17→        mode: 'limited'
    18→    }
    19→};
    20→
    21→// Action types
    22→const ActionTypes = {
    23→    SET_CURRENT_SESSION: 'SET_CURRENT_SESSION',
    24→    SET_SESSIONS: 'SET_SESSIONS',
    25→    SET_MESSAGES: 'SET_MESSAGES',
    26→    ADD_MESSAGE: 'ADD_MESSAGE',
    27→    SET_LOADING: 'SET_LOADING',
    28→    SET_ERROR: 'SET_ERROR',
    29→    SET_USER_PROPERTIES: 'SET_USER_PROPERTIES',
    30→    SET_CONNECTED: 'SET_CONNECTED',
    31→    SET_INITIALIZED: 'SET_INITIALIZED',
    32→    CLEAR_CHAT: 'CLEAR_CHAT',
    33→    SET_AUTH_STATUS: 'SET_AUTH_STATUS'
    34→};
    35→
    36→// Reducer
    37→function chatbotReducer(state, action) {
    38→    switch (action.type) {
    39→        case ActionTypes.SET_CURRENT_SESSION:
    40→            return {
    41→                ...state,
    42→                currentSession: action.payload,
    43→                error: null
    44→            };
    45→        case ActionTypes.SET_SESSIONS:
    46→            return {
    47→                ...state,
    48→                sessions: action.payload
    49→            };
    50→        case ActionTypes.SET_MESSAGES:
    51→            return {
    52→                ...state,
    53→                messages: action.payload
    54→            };
    55→        case ActionTypes.ADD_MESSAGE:
    56→            return {
    57→                ...state,
    58→                messages: [...state.messages, action.payload]
    59→            };
    60→        case ActionTypes.SET_LOADING:
    61→            return {
    62→                ...state,
    63→                isLoading: action.payload
    64→            };
    65→        case ActionTypes.SET_ERROR:
    66→            return {
    67→                ...state,
    68→                error: action.payload,
    69→                isLoading: false
    70→            };
    71→        case ActionTypes.SET_USER_PROPERTIES:
    72→            return {
    73→                ...state,
    74→                userProperties: action.payload
    75→            };
    76→        case ActionTypes.SET_CONNECTED:
    77→            return {
    78→                ...state,
    79→                isConnected: action.payload
    80→            };
    81→        case ActionTypes.SET_INITIALIZED:
    82→            return {
    83→                ...state,
    84→                isInitialized: action.payload
    85→            };
    86→        case ActionTypes.CLEAR_CHAT:
    87→            return {
    88→                ...state,
    89→                messages: [],
    90→                currentSession: null,
    91→                error: null
    92→            };
    93→        case ActionTypes.SET_AUTH_STATUS:
    94→            return {
    95→                ...state,
    96→                authStatus: action.payload
    97→            };
    98→        default:
    99→            return state;
   100→    }
   101→}
   102→
   103→// Context
   104→const ChatbotContext = createContext();
   105→
   106→// Provider component
   107→export function ChatbotProvider({ children }) {
   108→    const [state, dispatch] = useReducer(chatbotReducer, initialState);
   109→    const [api, setApi] = useState(null);
   110→
   111→    // Check authentication status and set appropriate API
   112→    useEffect(() => {
   113→        const { isAuthenticated, userId, mode } = checkAuthStatus();
   114→        dispatch({
   115→            type: ActionTypes.SET_AUTH_STATUS,
   116→            payload: { isAuthenticated, userId, mode }
   117→        });
   118→
   119→        // Set the appropriate API based on auth status
   120→        setApi(getChatbotAPI());
   121→    }, []);
   122→
   123→    // Initialize chatbot
   124→    useEffect(() => {
   125→        if (api) {
   126→            initializeChatbot();
   127→        }
   128→    }, [api]);
   129→
   130→    const initializeChatbot = async () => {
   131→        try {
   132→            dispatch({ type: ActionTypes.SET_LOADING, payload: true });
   133→
   134→            // Check if LangGraph service is healthy
   135→            const health = await api.health();
   136→            dispatch({ type: ActionTypes.SET_CONNECTED, payload: true });
   137→
   138→            // Get authentication status and load user data if authenticated
   139→            const { isAuthenticated, userId } = state.authStatus;
   140→            if (isAuthenticated && userId) {
   141→                try {
   142→                    // Load user's sessions
   143→                    const sessions = await api.getUserSessions(userId);
   144→                    dispatch({ type: ActionTypes.SET_SESSIONS, payload: sessions });
   145→
   146→                    // Load user properties
   147→                    const properties = await api.getUserProperties(userId);
   148→                    dispatch({ type: ActionTypes.SET_USER_PROPERTIES, payload: properties });
   149→
   150→                    // If no current session and there are existing sessions, use the most recent one
   151→                    if (sessions.length > 0 && !state.currentSession) {
   152→                        await loadSession(sessions[0].id);
   153→                    }
   154→                } catch (error) {
   155→                    console.error('Failed to load user data:', error);
   156→                    // Continue with limited mode if user data loading fails
   157→                }
   158→            }
   159→
   160→            dispatch({ type: ActionTypes.SET_INITIALIZED, payload: true });
   161→        } catch (error) {
   162→            console.error('Failed to initialize chatbot:', error);
   163→            dispatch({
   164→                type: ActionTypes.SET_ERROR,
   165→                payload: 'Failed to connect to chat service. Please try again later.'
   166→            });
   167→            dispatch({ type: ActionTypes.SET_CONNECTED, payload: false });
   168→        } finally {
   169→            dispatch({ type: ActionTypes.SET_LOADING, payload: false });
   170→        }
   171→    };
   172→
   173→    const createSession = async (userId) => {
   174→        try {
   175→            dispatch({ type: ActionTypes.SET_LOADING, payload: true });
   176→
   177→            const newSessionData = await api.createSession(userId);
   178→            const newSession = {
   179→                id: newSessionData.session_id,
   180→                user_id: userId,
   181→                title: "New Conversation",
   182→                created_at: new Date().toISOString(),
   183→                updated_at: new Date().toISOString(),
   184→                message_count: 0,
   185→                context: {}
   186→            };
   187→            dispatch({ type: ActionTypes.SET_CURRENT_SESSION, payload: newSession });
   188→            dispatch({ type: ActionTypes.SET_SESSIONS, payload: [newSession, ...state.sessions] });
   189→
   190→            return newSession;
   191→        } catch (error) {
   192→            console.error('Failed to create session:', error);
   193→            dispatch({
   194→                type: ActionTypes.SET_ERROR,
   195→                payload: 'Failed to create new chat session.'
   196→            });
   197→            throw error;
   198→        } finally {
   199→            dispatch({ type: ActionTypes.SET_LOADING, payload: false });
   200→        }
   201→    };
   202→
   203→    const loadSession = async (sessionId) => {
   204→        try {
   205→            dispatch({ type: ActionTypes.SET_LOADING, payload: true });
   206→
   207→            const session = await api.getSession(sessionId);
   208→            dispatch({ type: ActionTypes.SET_CURRENT_SESSION, payload: session });
   209→
   210→            // Load messages for this session (this would need to be implemented in the backend)
   211→            // For now, we'll start with empty messages
   212→            dispatch({ type: ActionTypes.SET_MESSAGES, payload: [] });
   213→
   214→            return session;
   215→        } catch (error) {
   216→            console.error('Failed to load session:', error);
   217→            dispatch({
   218→                type: ActionTypes.SET_ERROR,
   219→                payload: 'Failed to load chat session.'
   220→            });
   221→            throw error;
   222→        } finally {
   223→            dispatch({ type: ActionTypes.SET_LOADING, payload: false });
   224→        }
   225→    };
   226→
   227→    const sendMessage = async (message, sessionId = null) => {
   228→        const currentSessionId = sessionId || state.currentSession?.id;
   229→
   230→        if (!currentSessionId) {
   231→            throw new Error('No active session');
   232→        }
   233→
   234→        try {
   235→            dispatch({ type: ActionTypes.SET_LOADING, payload: true });
   236→
   237→            // Add user message to UI immediately
   238→            const userMessage = {
   239→                id: Date.now().toString(),
   240→                content: message,
   241→                role: 'user',
   242→                timestamp: new Date().toISOString(),
   243→                pending: true
   244→            };
   245→
   246→            dispatch({ type: ActionTypes.ADD_MESSAGE, payload: userMessage });
   247→
   248→            // Send message to LangGraph service
   249→            const response = await api.chat(message, currentSessionId);
   250→
   251→            // Remove pending flag and update with AI response
   252→            const updatedUserMessage = {
   253→                ...userMessage,
   254→                pending: false
   255→            };
   256→
   257→            const aiMessage = {
   258→                id: response.session_id || Date.now().toString(),
   259→                content: response.response?.content || response.response || 'I apologize, but I had trouble processing your request.',
   260→                role: 'assistant',
   261→                timestamp: new Date().toISOString(),
   262→                sources: response.sources || [],
   263→                metadata: response.metadata || response.context || {},
   264→                patent_urls: response.response?.patent_urls || []
   265→            };
   266→
   267→            dispatch({ type: ActionTypes.SET_MESSAGES, payload: [...state.messages.filter(msg => msg.id !== userMessage.id), updatedUserMessage, aiMessage] });
   268→
   269→            return aiMessage;
   270→        } catch (error) {
   271→            console.error('Failed to send message:', error);
   272→
   273→            // Update user message to show error
   274→            const errorMessage = {
   275→                ...state.messages[state.messages.length - 1],
   276→                pending: false,
   277→                content: 'Sorry, I encountered an error. Please try again.',
   278→                error: true
   279→            };
   280→
   281→            dispatch({
   282→                type: ActionTypes.SET_MESSAGES,
   283→                payload: [...state.messages.slice(0, -1), errorMessage]
   284→            });
   285→
   286→            dispatch({
   287→                type: ActionTypes.SET_ERROR,
   288→                payload: 'Failed to send message. Please try again.'
   289→            });
   290→
   291→            throw error;
   292→        } finally {
   293→            dispatch({ type: ActionTypes.SET_LOADING, payload: false });
   294→        }
   295→    };
   296→
   297→    const setUserProperties = async (userId, properties) => {
   298→        try {
   299→            await api.setUserProperties(userId, properties);
   300→            dispatch({ type: ActionTypes.SET_USER_PROPERTIES, payload: properties });
   301→        } catch (error) {
   302→            console.error('Failed to set user properties:', error);
   303→            throw error;
   304→        }
   305→    };
   306→
   307→    const clearChat = () => {
   308→        dispatch({ type: ActionTypes.CLEAR_CHAT });
   309→    };
   310→
   311→    const refreshSessions = async (userId) => {
   312→        try {
   313→            const sessions = await api.getUserSessions(userId);
   314→            dispatch({ type: ActionTypes.SET_SESSIONS, payload: sessions });
   315→            return sessions;
   316→        } catch (error) {
   317→            console.error('Failed to refresh sessions:', error);
   318→            throw error;
   319→        }
   320→    };
   321→
   322→    // Re-initialize when auth status changes
   323→    const value = {
   324→        ...state,
   325→        createSession,
   326→        loadSession,
   327→        sendMessage,
   328→        setUserProperties,
   329→        clearChat,
   330→        refreshSessions,
   331→        initializeChatbot,
   332→        api
   333→    };
   334→
   335→    return (
   336→        <ChatbotContext.Provider value={value}>
   337→            {children}
   338→        </ChatbotContext.Provider>
   339→    );
   340→}
   341→
   342→// Hook to use the chatbot context
   343→export function useChatbot() {
   344→    const context = useContext(ChatbotContext);
   345→    if (!context) {
   346→        throw new Error('useChatbot must be used within a ChatbotProvider');
   347→    }
   348→    return context;
   349→}
   350→
   351→export default ChatbotContext;

