import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { FileText, Database, Activity, Plus, TrendingUp, ArrowRight } from 'lucide-react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import StatCard from '../components/Dashboard/StatCard';
import RecentReports from '../components/Dashboard/RecentReports';
import api from '../api/axios';

const Dashboard = () => {
    const { user } = useAuth();
    const [stats, setStats] = useState({
        totalReports: 0,
        totalPatents: 0,
        credits: 0
    });
    const [recentReports, setRecentReports] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDashboardData = async () => {
            try {
                const reportsRes = await api.get('/reports/?skip=0&limit=5');
                const reports = reportsRes.data;
                setRecentReports(reports);

                setStats({
                    totalReports: reports.length,
                    totalPatents: 12503,
                    credits: 500
                });

                if (user?.is_admin) {
                    try {
                        const adminStats = await api.get('/admin/statistics');
                        setStats(prev => ({
                            ...prev,
                            totalPatents: adminStats.data.total_patents,
                            totalReports: adminStats.data.total_reports
                        }));
                    } catch (err) {
                        console.warn("Failed to fetch admin stats", err);
                    }
                }

            } catch (error) {
                console.error("Failed to fetch dashboard data", error);
            } finally {
                setLoading(false);
            }
        };

        if (user) {
            fetchDashboardData();
        }
    }, [user]);

    const statCards = [
        {
            title: 'Active Reports',
            value: stats.totalReports,
            icon: FileText,
            color: 'bg-indigo-50 text-indigo-600',
            trend: 12
        },
        {
            title: 'Analyzed Patents',
            value: stats.totalPatents.toLocaleString(),
            icon: Database,
            color: 'bg-emerald-50 text-emerald-600',
            trend: 5
        },
        {
            title: 'AI Credits',
            value: stats.credits,
            icon: Activity,
            color: 'bg-amber-50 text-amber-600',
            trend: 0
        },
    ];

    if (loading) {
        return (
            <div className="flex h-[60vh] items-center justify-center">
                <div className="text-center">
                    <div className="spinner-border text-indigo-600" role="status">
                        <span className="visually-hidden">Loading...</span>
                    </div>
                    <p className="mt-4 text-slate-500 font-medium">Syncing with patent intelligence...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-[1600px] mx-auto space-y-10 p-2 md:p-6">
            {/* Header */}
            <header className="flex flex-col md:row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 tracking-tight">
                        Intel Intelligence Dashboard
                    </h1>
                    <p className="text-slate-500 mt-1 flex items-center gap-2">
                        Welcome back, <span className="font-semibold text-indigo-600">{user?.full_name || user?.username}</span>
                        <span className="h-1 w-1 rounded-full bg-slate-300"></span>
                        Last updated: {new Date().toLocaleDateString()}
                    </p>
                </div>
                <div className="flex items-center gap-3">
                    <Link
                        to="/reports"
                        className="premium-button-primary flex items-center gap-2"
                    >
                        <Plus className="w-5 h-5" /> New Analysis
                    </Link>
                </div>
            </header>

            {/* Stats Grid */}
            <section className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {statCards.map((stat, index) => (
                    <motion.div
                        key={index}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: index * 0.1 }}
                        className="premium-card p-6"
                    >
                        <div className="flex justify-between items-start mb-4">
                            <div className={`${stat.color} p-3 rounded-xl`}>
                                <stat.icon className="w-6 h-6" />
                            </div>
                            {stat.trend > 0 && (
                                <span className="flex items-center gap-1 text-xs font-bold text-emerald-600 bg-emerald-50 px-2.5 py-1 rounded-full border border-emerald-100">
                                    <TrendingUp className="w-3 h-3" /> +{stat.trend}%
                                </span>
                            )}
                        </div>
                        <h3 className="text-slate-500 text-sm font-medium mb-1">{stat.title}</h3>
                        <div className="text-3xl font-bold text-slate-900 tracking-tight">{stat.value}</div>
                    </motion.div>
                ))}
            </section>

            {/* Main Content Area */}
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                {/* Recent Reports Section */}
                <section className="lg:col-span-8 space-y-6">
                    <div className="flex justify-between items-center">
                        <h2 className="text-xl font-bold text-slate-900">Recent Investigations</h2>
                        <Link to="/reports" className="text-indigo-600 text-sm font-semibold flex items-center gap-1 hover:underline">
                            View All <ArrowRight className="w-4 h-4" />
                        </Link>
                    </div>
                    <div className="premium-card overflow-hidden">
                        <RecentReports reports={recentReports} />
                    </div>
                </section>

                {/* Side Panel */}
                <aside className="lg:col-span-4 space-y-8">
                    {/* Pro Callout */}
                    <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden group">
                        <div className="relative z-10">
                            <h3 className="text-2xl font-bold mb-3 tracking-tight">Expand Your <br />Reach with Pro</h3>
                            <p className="text-slate-400 text-sm mb-6 leading-relaxed">Unlock advanced patent landscaping and real-time competitor tracking alerts.</p>
                            <button className="bg-white text-slate-900 w-full py-4 rounded-xl font-bold hover:bg-slate-50 transition-colors shadow-lg shadow-white/10">
                                Upgrade Workspace
                            </button>
                        </div>
                        <div className="absolute top-[-20%] right-[-10%] opacity-10 blur-3xl w-48 h-48 bg-indigo-500 rounded-full group-hover:bg-indigo-400 transition-colors duration-500"></div>
                    </div>

                    {/* Quick Search Card */}
                    <div className="premium-card p-8">
                        <h3 className="font-bold text-slate-900 text-lg mb-6">Omni-Search</h3>
                        <div className="space-y-4">
                            <div className="relative">
                                <input
                                    type="text"
                                    placeholder="Patent ID, Keyword, or IPC..."
                                    className="w-full pl-4 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none text-sm transition-all"
                                />
                            </div>
                            <button className="w-full bg-slate-950 text-white py-4 rounded-2xl font-bold hover:bg-slate-900 transition-all shadow-xl shadow-slate-200 active:scale-95">
                                Pulse Search
                            </button>
                        </div>
                        <div className="mt-6 flex flex-wrap gap-2">
                            <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400">Trending</span>
                            <span className="text-[10px] font-bold bg-indigo-50 text-indigo-600 px-2 py-1 rounded">Semiconductor</span>
                            <span className="text-[10px] font-bold bg-indigo-50 text-indigo-600 px-2 py-1 rounded">AR/VR</span>
                        </div>
                    </div>
                </aside>
            </div>
        </div>
    );
};

export default Dashboard;

from fastapi import APIRouter, Depends
from sqlalchemy.ext.asyncio import AsyncSession
from sqlalchemy import select, func, extract
from shared.database import get_db
from app.models import Patent, Report
from typing import Dict, Any
from datetime import datetime, timedelta

router = APIRouter()


@router.get("/overview")
async def get_analytics_overview(db: AsyncSession = Depends(get_db)):
    today = datetime.now()
    last_30_days = today - timedelta(days=30)
    last_year = today - timedelta(days=365)

    total_patents = await db.execute(select(func.count(Patent.patent_id)))
    total_patents_count = total_patents.scalar() or 0

    patents_last_30 = await db.execute(
        select(func.count(Patent.patent_id)).where(Patent.created_at >= last_30_days)
    )
    patents_last_30_count = patents_last_30.scalar() or 0

    patents_last_year = await db.execute(
        select(func.count(Patent.patent_id)).where(Patent.created_at >= last_year)
    )
    patents_last_year_count = patents_last_year.scalar() or 0

    total_reports = await db.execute(select(func.count(Report.id)))
    total_reports_count = total_reports.scalar() or 0

    reports_last_30 = await db.execute(
        select(func.count(Report.id)).where(Report.created_at >= last_30_days)
    )
    reports_last_30_count = reports_last_30.scalar() or 0

    return {
        "total_patents": total_patents_count,
        "patents_last_30_days": patents_last_30_count,
        "patents_last_year": patents_last_year_count,
        "total_reports": total_reports_count,
        "reports_last_30_days": reports_last_30_count,
    }


@router.get("/patents/timeline")
async def get_patents_timeline(db: AsyncSession = Depends(get_db), days: int = 365):
    start_date = datetime.now() - timedelta(days=days)

    timeline_query = (
        select(
            func.date(Patent.created_at).label("date"),
            func.count(Patent.patent_id).label("count"),
        )
        .where(Patent.created_at >= start_date)
        .group_by(func.date(Patent.created_at))
        .order_by(func.date(Patent.created_at))
    )

    result = await db.execute(timeline_query)
    timeline_data = result.all()

    return {
        "timeline": [
            {"date": str(row.date), "count": row.count} for row in timeline_data
        ]
    }


@router.get("/patents/by-month")
async def get_patents_by_month(db: AsyncSession = Depends(get_db), months: int = 12):
    start_date = datetime.now() - timedelta(days=months * 30)

    monthly_query = (
        select(
            extract("year", Patent.created_at).label("year"),
            extract("month", Patent.created_at).label("month"),
            func.count(Patent.patent_id).label("count"),
        )
        .where(Patent.created_at >= start_date)
        .group_by(
            extract("year", Patent.created_at),
            extract("month", Patent.created_at),
        )
        .order_by(
            extract("year", Patent.created_at),
            extract("month", Patent.created_at),
        )
    )

    result = await db.execute(monthly_query)
    monthly_data = result.all()

    return {
        "monthly": [
            {
                "year": int(row.year),
                "month": int(row.month),
                "month_name": datetime(2000, int(row.month), 1).strftime("%B"),
                "count": row.count,
            }
            for row in monthly_data
        ]
    }


@router.get("/patents/by-status")
async def get_patents_by_status(db: AsyncSession = Depends(get_db)):
    status_query = select(Patent.status, func.count(Patent.patent_id)).group_by(
        Patent.status
    )

    result = await db.execute(status_query)
    status_data = result.all()

    total_count = sum(row[1] for row in status_data)

    return {
        "status_distribution": [
            {
                "status": row[0],
                "count": row[1],
                "percentage": round((row[1] / total_count * 100), 2)
                if total_count > 0
                else 0,
            }
            for row in status_data
        ],
        "total_count": total_count,
    }


@router.get("/patents/top-assignees")
async def get_top_assignees(db: AsyncSession = Depends(get_db), limit: int = 10):
    assignee_query = (
        select(Patent.assignee, func.count(Patent.patent_id))
        .where(Patent.assignee.isnot(None))
        .group_by(Patent.assignee)
        .order_by(func.count(Patent.patent_id).desc())
        .limit(limit)
    )

    result = await db.execute(assignee_query)
    assignee_data = result.all()

    return {
        "top_assignees": [
            {"assignee": row[0], "patent_count": row[1]} for row in assignee_data
        ]
    }


@router.get("/patents/filing-trends")
async def get_filing_trends(db: AsyncSession = Depends(get_db), years: int = 5):
    current_year = datetime.now().year
    start_year = current_year - years

    filing_trends_query = (
        select(
            extract("year", Patent.filing_date).label("year"),
            func.count(Patent.patent_id).label("count"),
        )
        .where(
            Patent.filing_date.isnot(None),
            extract("year", Patent.filing_date) >= start_year,
        )
        .group_by(extract("year", Patent.filing_date))
        .order_by(extract("year", Patent.filing_date))
    )

    result = await db.execute(filing_trends_query)
    trends_data = result.all()

    return {
        "filing_trends": [
            {"year": int(row.year), "patent_count": row.count} for row in trends_data
        ]
    }


@router.get("/reports/analytics")
async def get_reports_analytics(db: AsyncSession = Depends(get_db)):
    total_reports = await db.execute(select(func.count(Report.id)))
    total_reports_count = total_reports.scalar() or 0

    report_types_query = select(Report.report_type, func.count(Report.id)).group_by(
        Report.report_type
    )

    result = await db.execute(report_types_query)
    report_types = result.all()

    return {
        "total_reports": total_reports_count,
        "report_types": [{"type": row[0], "count": row[1]} for row in report_types],
    }


@router.get("/dashboard")
async def get_dashboard_data(db: AsyncSession = Depends(get_db)):
    overview = await get_analytics_overview(db)
    timeline = await get_patents_timeline(db, days=30)
    by_status = await get_patents_by_status(db)
    top_assignees = await get_top_assignees(db, limit=5)
    filing_trends = await get_filing_trends(db, years=3)
    reports_analytics = await get_reports_analytics(db)

    return {
        "overview": overview,
        "timeline": timeline,
        "status_distribution": by_status,
        "top_assignees": top_assignees,
        "filing_trends": filing_trends,
        "reports": reports_analytics,
    }

