import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { FileText, Database, Activity, Plus, TrendingUp, ArrowRight } from 'lucide-react';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';
import StatCard from '../components/Dashboard/StatCard';
import RecentReports from '../components/Dashboard/RecentReports';
import api from '../api/axios';

const Dashboard = () => {
    const { user } = useAuth();
    const [stats, setStats] = useState({
        totalReports: 0,
        totalPatents: 0,
        credits: 0
    });
    const [recentReports, setRecentReports] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDashboardData = async () => {
            try {
                const reportsRes = await api.get('/reports/?skip=0&limit=5');
                const reports = reportsRes.data;
                setRecentReports(reports);

                setStats({
                    totalReports: reports.length,
                    totalPatents: 12503,
                    credits: 500
                });

                if (user?.is_admin) {
                    try {
                        const adminStats = await api.get('/admin/statistics');
                        setStats(prev => ({
                            ...prev,
                            totalPatents: adminStats.data.total_patents,
                            totalReports: adminStats.data.total_reports
                        }));
                    } catch (err) {
                        console.warn("Failed to fetch admin stats", err);
                    }
                }

            } catch (error) {
                console.error("Failed to fetch dashboard data", error);
            } finally {
                setLoading(false);
            }
        };

        if (user) {
            fetchDashboardData();
        }
    }, [user]);

    const statCards = [
        {
            title: 'Active Reports',
            value: stats.totalReports,
            icon: FileText,
            color: 'bg-indigo-50 text-indigo-600',
            trend: 12
        },
        {
            title: 'Analyzed Patents',
            value: stats.totalPatents.toLocaleString(),
            icon: Database,
            color: 'bg-emerald-50 text-emerald-600',
            trend: 5
        },
        {
            title: 'AI Credits',
            value: stats.credits,
            icon: Activity,
            color: 'bg-amber-50 text-amber-600',
            trend: 0
        },
    ];

    if (loading) {
        return (
            <div className="flex h-[60vh] items-center justify-center">
                <div className="text-center">
                    <div className="spinner-border text-indigo-600" role="status">
                        <span className="visually-hidden">Loading...</span>
                    </div>
                    <p className="mt-4 text-slate-500 font-medium">Syncing with patent intelligence...</p>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-[1600px] mx-auto space-y-10 p-2 md:p-6">
            {/* Header */}
            <header className="flex flex-col md:row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-3xl font-bold text-slate-900 tracking-tight">
                        Intel Intelligence Dashboard
                    </h1>
                    <p className="text-slate-500 mt-1 flex items-center gap-2">
                        Welcome back, <span className="font-semibold text-indigo-600">{user?.full_name || user?.username}</span>
                        <span className="h-1 w-1 rounded-full bg-slate-300"></span>
                        Last updated: {new Date().toLocaleDateString()}
                    </p>
                </div>
                <div className="flex items-center gap-3">
                    <Link
                        to="/reports"
                        className="premium-button-primary flex items-center gap-2"
                    >
                        <Plus className="w-5 h-5" /> New Analysis
                    </Link>
                </div>
            </header>

            {/* Stats Grid */}
            <section className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {statCards.map((stat, index) => (
                    <motion.div
                        key={index}
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: index * 0.1 }}
                        className="premium-card p-6"
                    >
                        <div className="flex justify-between items-start mb-4">
                            <div className={`${stat.color} p-3 rounded-xl`}>
                                <stat.icon className="w-6 h-6" />
                            </div>
                            {stat.trend > 0 && (
                                <span className="flex items-center gap-1 text-xs font-bold text-emerald-600 bg-emerald-50 px-2.5 py-1 rounded-full border border-emerald-100">
                                    <TrendingUp className="w-3 h-3" /> +{stat.trend}%
                                </span>
                            )}
                        </div>
                        <h3 className="text-slate-500 text-sm font-medium mb-1">{stat.title}</h3>
                        <div className="text-3xl font-bold text-slate-900 tracking-tight">{stat.value}</div>
                    </motion.div>
                ))}
            </section>

            {/* Main Content Area */}
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
                {/* Recent Reports Section */}
                <section className="lg:col-span-8 space-y-6">
                    <div className="flex justify-between items-center">
                        <h2 className="text-xl font-bold text-slate-900">Recent Investigations</h2>
                        <Link to="/reports" className="text-indigo-600 text-sm font-semibold flex items-center gap-1 hover:underline">
                            View All <ArrowRight className="w-4 h-4" />
                        </Link>
                    </div>
                    <div className="premium-card overflow-hidden">
                        <RecentReports reports={recentReports} />
                    </div>
                </section>

                {/* Side Panel */}
                <aside className="lg:col-span-4 space-y-8">
                    {/* Pro Callout */}
                    <div className="bg-slate-900 rounded-3xl p-8 text-white shadow-2xl relative overflow-hidden group">
                        <div className="relative z-10">
                            <h3 className="text-2xl font-bold mb-3 tracking-tight">Expand Your <br />Reach with Pro</h3>
                            <p className="text-slate-400 text-sm mb-6 leading-relaxed">Unlock advanced patent landscaping and real-time competitor tracking alerts.</p>
                            <button className="bg-white text-slate-900 w-full py-4 rounded-xl font-bold hover:bg-slate-50 transition-colors shadow-lg shadow-white/10">
                                Upgrade Workspace
                            </button>
                        </div>
                        <div className="absolute top-[-20%] right-[-10%] opacity-10 blur-3xl w-48 h-48 bg-indigo-500 rounded-full group-hover:bg-indigo-400 transition-colors duration-500"></div>
                    </div>

                    {/* Quick Search Card */}
                    <div className="premium-card p-8">
                        <h3 className="font-bold text-slate-900 text-lg mb-6">Omni-Search</h3>
                        <div className="space-y-4">
                            <div className="relative">
                                <input
                                    type="text"
                                    placeholder="Patent ID, Keyword, or IPC..."
                                    className="w-full pl-4 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none text-sm transition-all"
                                />
                            </div>
                            <button className="w-full bg-slate-950 text-white py-4 rounded-2xl font-bold hover:bg-slate-900 transition-all shadow-xl shadow-slate-200 active:scale-95">
                                Pulse Search
                            </button>
                        </div>
                        <div className="mt-6 flex flex-wrap gap-2">
                            <span className="text-[10px] uppercase tracking-wider font-bold text-slate-400">Trending</span>
                            <span className="text-[10px] font-bold bg-indigo-50 text-indigo-600 px-2 py-1 rounded">Semiconductor</span>
                            <span className="text-[10px] font-bold bg-indigo-50 text-indigo-600 px-2 py-1 rounded">AR/VR</span>
                        </div>
                    </div>
                </aside>
            </div>
        </div>
    );
};

export default Dashboard;

from fastapi import FastAPI, Request
import logging
import asyncio
from datetime import datetime
from typing import Dict, Any
import httpx
from fastapi.middleware.cors import CORSMiddleware
from app.api.v1.api import api_router
from app.routes import web_router
from app.core.config import settings
import json
import time
from fastapi.staticfiles import StaticFiles
from fastapi.responses import JSONResponse, FileResponse
import os

frontend_dist_path = os.path.abspath(
    os.path.join(os.path.dirname(__file__), "../../front_end/dist")
)

# Custom JSON Formatter
class JsonFormatter(logging.Formatter):
    def format(self, record):
        log_record = {
            "timestamp": datetime.utcnow().isoformat(),
            "level": record.levelname,
            "message": record.getMessage(),
            "module": record.module,
            "funcName": record.funcName,
        }
        if record.exc_info:
            log_record["exception"] = self.formatException(record.exc_info)
        return json.dumps(log_record)


# Initialize logging based on environment
def setup_logging():
    level = logging.DEBUG if settings.DEBUG else logging.INFO
    root_logger = logging.getLogger()
    root_logger.setLevel(level)

    # Remove existing handlers
    for handler in root_logger.handlers[:]:
        root_logger.removeHandler(handler)

    handler = logging.StreamHandler()
    if settings.ENVIRONMENT == "production":
        handler.setFormatter(JsonFormatter())
    else:
        # Standard formatted output for development
        formatter = logging.Formatter("%(levelname)s: [%(name)s] %(message)s")
        handler.setFormatter(formatter)

    root_logger.addHandler(handler)


setup_logging()
logger = logging.getLogger(__name__)

app = FastAPI(
    title="Patent Board", version="1.0.0", description="Patent Analysis Board Backend"
)


@app.exception_handler(Exception)
async def global_exception_handler(request: Request, exc: Exception):
    logger.error(f"Global exception: {exc}", exc_info=True)
    return JSONResponse(
        status_code=500,
        content={"message": "Internal Server Error", "detail": str(exc)},
    )


# CORS Configuration
origins = []

# Add origins from settings
if settings.BACKEND_CORS_ORIGINS:
    if isinstance(settings.BACKEND_CORS_ORIGINS, str):
        try:
            origins.extend(json.loads(settings.BACKEND_CORS_ORIGINS))
        except (ValueError, TypeError):
            origins.extend([o.strip() for o in settings.BACKEND_CORS_ORIGINS.split(",")])
    else:
        origins.extend(settings.BACKEND_CORS_ORIGINS)

# Add default localhost ports for development
origins.extend([
    "http://localhost:3000",
    "http://localhost:3300",
    "http://localhost:8001",
    "http://localhost:8080",
    "http://localhost:5000",
    "http://127.0.0.1:8080",
    "http://127.0.0.1:5000",
])

origins = list(set(origins))  # Remove duplicates

# In DEBUG mode, allow all origins via regex to support various network IPs
allow_origin_regex = None
if settings.DEBUG:
    allow_origin_regex = r"^https?://.*$"
    origins = [] # Regex takes precedence

app.add_middleware(
    CORSMiddleware,
    allow_origins=origins,
    allow_origin_regex=allow_origin_regex,
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)


# Request Logging Middleware
@app.middleware("http")
async def log_requests(request: Request, call_next):
    start_time = time.time()
    response = await call_next(request)
    duration = time.time() - start_time

    logger.info(
        f"Request: {request.method} {request.url.path} "
        f"Status: {response.status_code} "
        f"Duration: {duration:.4f}s"
    )
    return response


# Include API Router
app.include_router(api_router, prefix="/api/v1")

# Include Web Router (Empty legacy router)
app.include_router(web_router)


async def check_mariadb() -> Dict[str, Any]:
    """Check MariaDB connectivity"""
    try:
        from shared.database import AsyncSessionLocal

        async with AsyncSessionLocal() as db:
            from sqlalchemy import text

            result = await db.execute(text("SELECT 1"))
            await result.fetchone()
            return {"status": "healthy", "message": "Connected"}
    except Exception as e:
        logger.error(f"MariaDB health check failed: {e}")
        return {"status": "unhealthy", "message": str(e)}


async def check_neo4j() -> Dict[str, Any]:
    """Check Neo4j connectivity"""
    try:
        from neo4j import AsyncGraphDatabase

        driver = AsyncGraphDatabase.driver(
            settings.NEO4J_URI, auth=(settings.NEO4J_USER, settings.NEO4J_PASSWORD)
        )
        async with driver.session() as session:
            result = await session.run("RETURN 1 as num")
            record = await result.single()
            await driver.close()
            if record and record["num"] == 1:
                return {"status": "healthy", "message": "Connected"}
            return {"status": "unhealthy", "message": "Unexpected response"}
    except Exception as e:
        logger.error(f"Neo4j health check failed: {e}")
        return {"status": "unhealthy", "message": str(e)}


async def check_mcp_server() -> Dict[str, Any]:
    """Check MCP server connectivity"""
    try:
        async with httpx.AsyncClient(timeout=5.0) as client:
            response = await client.get(f"{settings.MCP_SERVER_URL}/health")
            if response.status_code == 200:
                return {"status": "healthy", "message": "Connected"}
            return {"status": "unhealthy", "message": f"HTTP {response.status_code}"}
    except Exception as e:
        logger.error(f"MCP server health check failed: {e}")
        return {"status": "unhealthy", "message": str(e)}


async def check_redis() -> Dict[str, Any]:
    """Check Redis connectivity"""
    try:
        import redis.asyncio as redis

        client = redis.from_url(settings.REDIS_URL, socket_connect_timeout=5)
        await client.ping()
        await client.close()
        return {"status": "healthy", "message": "Connected"}
    except Exception as e:
        logger.error(f"Redis health check failed: {e}")
        return {"status": "unhealthy", "message": str(e), "optional": True}


@app.get("/health")
async def health_check():
    """Basic health check endpoint"""
    return {"status": "healthy", "timestamp": datetime.utcnow().isoformat()}


@app.get("/health/detailed")
async def health_check_detailed():
    """Detailed health check with service dependencies"""
    start_time = datetime.utcnow()

    # Run all checks concurrently
    results = await asyncio.gather(
        check_mariadb(),
        check_neo4j(),
        check_mcp_server(),
        check_redis(),
        return_exceptions=True,
    )

    checks = {
        "mariadb": results[0]
        if not isinstance(results[0], Exception)
        else {"status": "unhealthy", "message": str(results[0])},
        "neo4j": results[1]
        if not isinstance(results[1], Exception)
        else {"status": "unhealthy", "message": str(results[1])},
        "mcp_server": results[2]
        if not isinstance(results[2], Exception)
        else {"status": "unhealthy", "message": str(results[2])},
        "redis": results[3]
        if not isinstance(results[3], Exception)
        else {"status": "unhealthy", "message": str(results[3]), "optional": True},
    }

    # Determine overall status
    critical_services = ["mariadb", "neo4j", "mcp_server"]
    all_healthy = all(
        checks[service]["status"] == "healthy" for service in critical_services
    )

    end_time = datetime.utcnow()
    response_time_ms = (end_time - start_time).total_seconds() * 1000

    status_code = 200 if all_healthy else 503

    return JSONResponse(
        status_code=status_code,
        content={
            "status": "healthy" if all_healthy else "degraded",
            "timestamp": end_time.isoformat(),
            "response_time_ms": round(response_time_ms, 2),
            "version": settings.VERSION,
            "services": checks,
        },
    )


# Serve Frontend SPA - Defined at the end to avoid shadowing routes
if os.path.exists(frontend_dist_path):
    # Mount assets directory first
    assets_path = os.path.join(frontend_dist_path, "assets")
    if os.path.exists(assets_path):
        app.mount("/assets", StaticFiles(directory=assets_path), name="assets")

    # Catch-all route for SPA
    @app.get("/{full_path:path}")
    async def serve_spa(request: Request, full_path: str):
        # Check if requested path is an API call or health check
        if full_path.startswith("api/") or full_path.startswith("health"):
            return JSONResponse(status_code=404, content={"detail": "Not Found"})

        # Check if the file exists in the dist folder
        file_path = os.path.join(frontend_dist_path, full_path)
        if os.path.isfile(file_path):
            return FileResponse(file_path)

        # Fallback to index.html for SPA routing
        return FileResponse(os.path.join(frontend_dist_path, "index.html"))
else:
    logger.warning(f"Frontend dist directory not found at {frontend_dist_path}")

